SELECT metadata_key, metadata_value
FROM project_metadata
WHERE metadata_key = 'keywords';

SELECT p.project_id, pv.version_date
FROM projects p
JOIN project_versions pv ON p.project_id = pv.project_id
WHERE pv.version_date = (
    SELECT MAX(version_date) FROM project_versions
);

SELECT rdc_name
FROM rdcs
WHERE rdc_id = 1;

SELECT COUNT(p.project_id) AS total_projects_across_all_departments
FROM departments d
LEFT JOIN projects p ON d.dept_id = p.dept_id;
